const body = $json.body;

const remoteJid = body.data.key.remoteJid;

const telefone = remoteJid
  .replace("@s.whatsapp.net", "");

const mensagem =
  body.data.message?.conversation ||
  body.data.message?.extendedTextMessage?.text ||
  "";

return [
  {
    json: {
      telefone,
      mensagem,
      nome: body.data.pushName,
      messageId: body.data.key.id,
      instancia: body.instance,
      timestamp: body.date_time,
      fromMe: body.data.key.fromMe,
      startedAt: Date.now()
    }
  }
];

const resposta = $json.output.response || "";

return [{
  json: {
    ...$json,
    respostaValida: resposta.trim().length >= 3
  }
}];

const historico = $input.all();

let contexto = "";

historico.reverse().forEach(item => {

contexto += `Usuário: ${item.json.mensagem_usuario}\n`;

contexto += `Assistente: ${item.json.resposta_ia}\n\n`;

});

return [

{

json:{

...$('Normalize Evolution Payload').first().json,

conversation_history: contexto

}

}

];

return [
  {
    json: {

      intent: $input.first().json.output.intent || null,

      response: $input.first().json.output.response || null,

      procedure:
        $input.first().json.output.appointment.procedure || null,

      preferred_date:
        $input.first().json.output.appointment.date || null,

      preferred_time:
        $input.first().json.output.appointment.time || null
    }
  }
];
